import { useState, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';

import constFlaskURL from '../../consts/constFlaskURL'

import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function AddRoadSing() {
    const [road_id, setRoadID] = useState('');
    const [latitude, setLatitude] = useState('');
    const [longitude, setLongitude] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();
    const image = useRef();

    const file = image.current?.files?.[0];

    const handleLogout = async () => {
        setLoading(true);

        try 
        {
            const response = await constFlaskURL.post('/logout');

            if (response.status === 200) 
            {
                setTimeout(() => {
                    navigate('/login');
                }, 1000);
            }
        }
        catch (err) 
        {
            console.error('Logout error:', err);
        } 
        finally 
        {
            setLoading(false);
        }
    };

    const submitRoadSing = async (e) => {
        e.preventDefault();
        const road_sing = { road_id, file, latitude, longitude };

        try {
            const add_road_sing = await constFlaskURL.post('/roads/sings', road_sing, {
                headers: {
                    'Content-Type': 'multipart/form-data',
                    'Accept': 'application/json'
                }
            });

            if (add_road_sing.status === 201){
                setRoadID('');
                setLatitude('');
                setLongitude('');
                navigate('/roads/sings');
            }
        } catch (error) {
            console.log(error);
        }
    };

    return (
        <div>
            <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
                <div className="container-fluid py-2">
                    <Link className="navbar-brand fs-3 fw-bold" to="/main">roads_admin</Link>
                    <Link className="navbar-brand fs-3 fw-bold">
                        <button 
                            onClick={handleLogout} 
                                className="logout-button"
                                disabled={loading}
                            >
                            {loading ? (
                            <>
                                <span className="spinner"></span>
                                Выход...
                            </>
                            ) : 'Выйти'}
                        </button>
                    </Link>
                </div>
            </nav>
            <form className='container' onSubmit={submitRoadSing}>
                <div className='mb-3'>
                    <lable className='form-label'>ID дороги</lable>
                    <input 
                        type='text'
                        name='road_id' 
                        value={road_id.road_id} 
                        onChange={(e) => setRoadID(e.target.value)}
                        className='form-input'  
                        placeholder='ID дороги'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Изображение</lable>
                    <input 
                        type='file'
                        name='image'
                        accept='../../../../src/app/recognition/img/*' 
                        value={image.image} 
                        placeholder='Изображение'
                        required  
                        multiple
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Широта</lable>
                    <input 
                        type='text'
                        name='latitude' 
                        value={latitude.latitude} 
                        onChange={(e) => setLatitude(e.target.value)}
                        className='form-input'  
                        placeholder='Широта'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Долгота</lable>
                    <input 
                        type='text'
                        name='longitude' 
                        value={longitude.longitude} 
                        onChange={(e) => setLongitude(e.target.value)}
                        className='form-input'  
                        placeholder='Долгота'
                        required  
                    />
                </div>
                <button 
                    type='submit' 
                    className='btn btn-primary'
                >
                    Добавить
                </button>
                <button 
                    type='submit' 
                    className='btn btn-danger' 
                    onClick={() => navigate('/roads/sings')}
                >
                    Назад
                </button>
            </form>
        </div>
    )

};

export default AddRoadSing;
